UPDATE public.announcements SET title_ar = 'هدفنا 20,000 عضو في الديسكورد', title_en = 'Goal: 20,000 Discord members', excerpt_ar = 'مجتمعنا يكبر يوم بعد يوم — وهدفنا القادم الوصول إلى 20 ألف عضو.', body_ar = 'رحلتنا مستمرة وطموحنا أكبر — هدفنا القادم الوصول إلى 20,000 عضو في ديسكورد Lux Addons. كل عضو جديد يضيف نبضاً لهذا المجتمع، وقادم قريباً حدث خاص وباقات مجانية للأعضاء الأوائل بمجرد وصولنا للرقم.' WHERE slug = 'community-milestone';